# Prompt: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

def process_payment(user, cart_items, payment_details):
    # Define discount rates based on user roles
    discount_rates = {
        'basic': 0.0,
        'premium': 0.15,
        'enterprise': 0.30
    }
    
    # Get the discount rate for the user's role
    discount_rate = discount_rates.get(user.role, 0.0)
    
    # Calculate the total cart value
    total_cart_value = sum(item['price'] * item['quantity'] for item in cart_items)
    
    # Apply the discount to the total cart value
    discounted_amount = total_cart_value * (1 - discount_rate)
    
    # Process the payment (this is a placeholder for actual payment processing logic)
    # For now, we'll just print the payment details and discounted amount
    print(f"Processing payment for user: {user.name}")
    print(f"Payment Details: {payment_details}")
    print(f"Original Cart Total: ${total_cart_value:.2f}")
    print(f"Discounted Amount: ${discounted_amount:.2f}")
    
    # Return the discounted amount or a success status
    return discounted_amount

# Example usage:
class User:
    def __init__(self, name, role):
        self.name = name
        self.role = role

class Item:
    def __init__(self, price, quantity):
        self.price = price
